    def is_numeric_column(self, col_name):
        return pd.api.types.is_numeric_dtype(self.csv_data[col_name])
        
    def search_data(self):
        search_term1 = str(self.searchTerm1.text())
        search_term2 = str(self.searchTerm2.text())
        selected_col1 = self.column1CB.currentText()
        selected_col2 = self.column2CB.currentText()
        filter_text = self.filterCB.currentText()
        filtered_data = self.csv_data
        

        if not search_term1 or not selected_col1:
            return 
        
        # Apply first filter
        if self.is_numeric_column(selected_col1):
            try:
                search_value1 = float(search_term1)
                condition1 = self.csv_data[selected_col1] == search_value1
            except ValueError:
                return 
        else:
            condition1 = self.csv_data[selected_col1].str.contains(search_term1, case=False, na=False)
            
        if search_term2 and selected_col2:
            
            if self.is_numeric_column(selected_col2):
                try:
                    search_value2 = float(search_term2)
                    condition2 = self.csv_data[selected_col2] == search_value2
                except ValueError:
                    return 
            else:
                condition2 = self.csv_data[selected_col2].str.contains(search_term2, case=False, na=False)
                
            if filter_text == "AND":
                filtered_data = self.csv_data[condition1 & condition2]
            elif filter_text == "OR":
                filtered_data = self.csv_data[condition1 | condition2]
            elif filter_text == "NOT":
                filtered_data = self.csv_data[condition1 & ~condition2]
            else:
                filtered_data = self.csv_data[condition1]
        else:
            filtered_data = self.csv_data[condition1]

        self.populate_table(filtered_data)
        
    def load_csv(self):
        options = QtWidgets.QFileDialog.Options()
        options |= QtWidgets.QFileDialog.DontUseNativeDialog
        file_path, _ = QtWidgets.QFileDialog.getOpenFileName(None, "Open CSV", "", "CSV Files (*.csv);;All Files (*)", options=options)
        
        if file_path:
            try:
                self.csv_data = pd.read_csv(file_path)
                self.populate_table(self.csv_data)
                self.column1CB.addItems(self.csv_data.columns)
                self.column2CB.addItems(self.csv_data.columns)
            except Exception as e:
                QtWidgets.QMessageBox.critical(None, "Error", f"Could not load CSV file: {str(e)}")
                
                
    def populate_table(self, data_frame):
        self.table.setColumnCount(len(data_frame.columns))
        self.table.setRowCount(len(data_frame))
        self.table.setHorizontalHeaderLabels(data_frame.columns)
        
        for i in range(len(data_frame)):
            for j in range(len(data_frame.columns)):
                self.table.setItem(i, j, QtWidgets.QTableWidgetItem(str(data_frame.iloc[i, j])))


