    def resizeEvent(self, event):
        current_size = self.ui.centralwidget.size()
        if current_size.width() < 100 or current_size.height() < 100:
            super().resizeEvent(event)
            return
        scale_widget_geometries(self._widget_geometries, self._base_size, self.ui.centralwidget.size())
        super().resizeEvent(event)

    def go_back_to_main(self):
        self.main_window.show()
        self.close()
